MerchantConfig = {}
MerchantConfig.MerchantConfigs = {}

function MerchantConfig:initConfig(configs)
    for _, config in pairs(configs) do
        local item = {
            id = tonumber(config.id),
            actor = tostring(config.actor),
            name = tostring(config.name),
            storeId = tonumber(config.storeId),
            merchantPos = StringUtil.split(config.merchantPos, "#"),
            yaw = tonumber(config.yaw),
            monsterId = tonumber(config.monsterId)
        }
        self.MerchantConfigs[item.id] = item
        --ActorManager:createMerchantActor(item.id)
    end
end

function MerchantConfig:getConfigById(id)
    return self.MerchantConfigs[id]
end
